def lower_bound(nums: list[int], target: int) -> int:
    """
    二分查找变体：查找第一个 >= target 的位置（下界）
    常用于：插入位置、范围查询
    """
    left, right = 0, len(nums)  # 右开区间 [left, right)

    while left < right:  # 左闭右开，left == right 时结束
        mid = left + (right - left) // 2
        if nums[mid] < target:
            left = mid + 1   # mid 及左侧均不可能
        else:
            right = mid      # mid 可能是答案，保留

    return left  # 返回插入位置，可能等于 len(nums)


def find_first_and_last(nums: list[int], target: int) -> list[int]:
    """
    查找 target 在数组中的起始和结束位置
    """
    def find_bound(nums, target, is_first):
        # is_first=True 找第一个 >= target 的位置
        # is_first=False 找第一个 > target 的位置，再减一
        left, right = 0, len(nums)
        while left < right:
            mid = left + (right - left) // 2
            if (is_first and nums[mid] < target) or (not is_first and nums[mid] <= target):
                left = mid + 1
            else:
                right = mid
        return left

    first = find_bound(nums, target, True)
    last = find_bound(nums, target, False) - 1

    if first <= last and first < len(nums) and nums[first] == target:
        return [first, last]
    return [-1, -1]
